// Check if we got any emails in the batch
const items = $input.all();
const firstItem = items[0]?.json;
// RPC returns array — if empty array or null, nothing to process
if (!firstItem || (Array.isArray(firstItem) && firstItem.length === 0)) {
  return [{ json: { _empty: true } }];
}
// If the response is an array at top level, split into individual items
if (Array.isArray(firstItem)) {
  return firstItem.map(row => ({ json: row }));
}
// Single object
if (firstItem.id) {
  return items;
}
return [{ json: { _empty: true } }];

// Parse AI classification response and normalize to live schema contracts
const VALID_CATEGORIES = ['production','sales','finance','retail','marketplace','regulatory','customer','compliance','noise'];
const VALID_PRIORITIES = ['critical','important','informational','noise'];
const VALID_CONFIDENCE = ['high','medium','low'];
const VALID_TRIGGERS = ['distributor_response','payment_issue','production_decision','external_response_draft','commitment',null];
const TRIGGER_NORMALIZE = {
  regulatory_flag: 'external_response_draft',
  inventory_reorder: 'production_decision',
  pricing_change: 'commitment',
  new_partnership: 'distributor_response',
  legal_notice: 'external_response_draft',
  none: null,
};
const CONF_SCORE = { high: 0.9, medium: 0.6, low: 0.3 };

const emailData = $('IF Has Emails').item.json;
const emailId = emailData.id;
let parsed;

try {
  const content = $json?.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch (e) {
  return [{
    json: {
      email_id: emailId,
      ...emailData,
      status: 'error',
      classifier_error: 'JSON parse failed: ' + e.message,
      needs_human_review: true,
      classification_confidence: CONF_SCORE.low,
      confidence_label: 'low',
      classifying_worker_id: null,
      classification_started_at: null,
      _parse_ok: false,
    }
  }];
}

if (!VALID_CATEGORIES.includes(parsed.category)) parsed.category = 'noise';
if (!VALID_PRIORITIES.includes(parsed.priority)) parsed.priority = 'informational';
if (!VALID_CONFIDENCE.includes(parsed.classification_confidence)) parsed.classification_confidence = 'low';
if (parsed.approval_trigger in TRIGGER_NORMALIZE) parsed.approval_trigger = TRIGGER_NORMALIZE[parsed.approval_trigger];
if (!VALID_TRIGGERS.includes(parsed.approval_trigger)) parsed.approval_trigger = null;
if (!Array.isArray(parsed.secondary_categories)) parsed.secondary_categories = [];
if (!Array.isArray(parsed.routed_agent_names)) parsed.routed_agent_names = [];

const confidenceLabel = parsed.classification_confidence;
const confidenceScore = CONF_SCORE[confidenceLabel] ?? CONF_SCORE.low;
const needsReview = Boolean(parsed.needs_human_review) || confidenceLabel === 'low';

return [{
  json: {
    email_id: emailId,
    ...emailData,
    ...parsed,
    status: 'triaged',
    needs_human_review: needsReview,
    classification_confidence: confidenceScore,
    confidence_label: confidenceLabel,
    classifying_worker_id: null,
    classification_started_at: null,
    classifier_error: null,
    _parse_ok: true,
  }
}];

// Map classifier trigger to approvals contract fields
const TRIGGER_MAP = {
  distributor_response: 'contact_distributor',
  payment_issue: 'commit_funds',
  production_decision: 'schedule_production',
  external_response_draft: 'send_email',
  commitment: 'commit_funds',
  // Defensive mapping for legacy labels
  regulatory_flag: 'send_email',
  inventory_reorder: 'schedule_production',
  pricing_change: 'commit_funds',
  new_partnership: 'contact_distributor',
  legal_notice: 'send_email',
};

const trigger = $json.approval_trigger;
const actionType = TRIGGER_MAP[trigger] || 'other';
const priority = $json.priority || 'informational';
const riskLevel = priority === 'critical' ? 'critical' : (priority === 'important' ? 'medium' : 'low');
const confidenceLabel = $json.confidence_label || ($json.classification_confidence >= 0.8 ? 'high' : ($json.classification_confidence >= 0.5 ? 'medium' : 'low'));
const permissionTier = ['payment_issue', 'commitment', 'production_decision'].includes(trigger) ? 3 : 2;

return [{
  json: {
    requesting_agent_id: '551b7a78-44be-473d-8207-aed5e7f3480e',
    action_type: actionType,
    target_entity_type: 'email_events',
    target_entity_id: $json.email_id,
    summary: ($json.summary || ('Review email: ' + ($json.subject || 'No subject'))).substring(0, 500),
    supporting_data: JSON.stringify({
      email_id: $json.email_id,
      sender_email: $json.sender_email,
      subject: $json.subject,
      category: $json.category,
      priority: $json.priority,
      suggested_action: $json.suggested_action || null,
    }),
    confidence: confidenceLabel,
    confidence_level: Number(($json.classification_confidence ?? 0.3).toFixed(2)),
    risk_level: riskLevel,
    risk_assessment: riskLevel,
    permission_tier: permissionTier,
    status: 'pending',
    action_pattern: trigger || null,
    action_proposed: ($json.suggested_action || $json.summary || '').substring(0, 500),
    approval_trigger: trigger || null,
  }
}];
